import scala.util.Random
import scala.collection.mutable.ArrayBuffer // For mutable buffer example

object RandomNumberDemo {
  def main(args: Array[String]): Unit = {
    // Default random number generator
    val random = new Random()

    // Seed the generator (optional, good for reproducible tests)
    // random.setSeed(42L) // Example fixed seed

    println("--- Random Numbers ---")
    // Generate a random integer between min (inclusive) and max (exclusive)
    val minInt = 1
    val maxIntExclusive = 101 // To include 100
    // nextInt(n) generates 0 to n-1, so need max - min
    val randomInt = minInt + random.nextInt(maxIntExclusive - minInt)
    println(s"Random Integer ($minInt-${maxIntExclusive - 1}): $randomInt")

    // Generate a random double between min (inclusive) and max (exclusive)
    val minDouble = 0.0
    val maxDouble = 1.0
    // nextDouble generates 0.0 to 1.0 (exclusive of 1.0)
    val randomDouble = minDouble + (maxDouble - minDouble) * random.nextDouble()
    println(s"Random Double [$minDouble,$maxDouble): $randomDouble")

    // Generate a random boolean
    val randomBoolean = random.nextBoolean()
    println(s"Random Boolean: $randomBoolean")

    println("\n--- Random Selection ---")
    // Select a random element from a sequence (List, Array, Vector, etc.)
    val fruits = List("apple", "banana", "cherry", "date")
    if (fruits.nonEmpty) {
      val randomFruit = fruits(random.nextInt(fruits.length)) // Or use Random.shuffle(fruits).headOption
      println(s"Random fruit from $fruits: $randomFruit")
    } else {
      println("Fruit list is empty.")
    }

    println("\n--- Shuffling ---")
    // Shuffle a sequence
    val shuffledFruits = Random.shuffle(fruits)
    println(s"Shuffled fruits: $shuffledFruits")

    // Generating random byte arrays
    val bytes = new Array[Byte](10)
    random.nextBytes(bytes)
    println(s"Random bytes: ${bytes.mkString("[", ", ", "]")}")
  }
}

