import scala.collection.immutable.StringOps // Provides .reverse on String

object ReverseStringDemo {
  def main(args: Array[String]): Unit = {
    val original = "Hello Scala!"
    val originalUnicode = "你好 Scala" // Example with Unicode

    // Method 1: Using the built-in reverse method on String
    // This is the simplest and most idiomatic way in Scala.
    // It correctly handles Unicode characters (UTF-16 internally).
    val reversed = original.reverse
    val reversedUnicode = originalUnicode.reverse

    println(s"Original: '$original'")
    println(s"Reversed: '$reversed'")
    println("\n--- Unicode ---")
    println(s"Original Unicode: '$originalUnicode'")
    println(s"Reversed Unicode: '$reversedUnicode'")

    // Method 2: Manual reversal using indices (less common for strings)
    // More complex and error-prone, especially with Unicode.
    def manualReverse(s: String): String = {
      if (s == null || s.length <= 1) {
        s
      } else {
        val chars = s.toCharArray
        val n = chars.length
        for (i <- 0 until n / 2) {
          val temp = chars(i)
          chars(i) = chars(n - 1 - i)
          chars(n - 1 - i) = temp
        }
        new String(chars)
      }
    }

    println("\n--- Manual (Less Idiomatic) ---")
    println(s"Manually Reversed: '${manualReverse(original)}'")
    // Note: Manual reverse on UTF-16 surrogate pairs might break characters.
    // The built-in .reverse is safer.
  }
}

