import scala.math.BigInt // For handling potentially large Fibonacci numbers

object FibonacciDemo {

  // Iterative function to calculate the Nth Fibonacci number (0-indexed)
  // Returns BigInt to prevent overflow.
  def fibonacciIterative(n: Int): BigInt = {
    if (n < 0) throw new IllegalArgumentException("Input must be non-negative")
    if (n == 0) return BigInt(0)
    if (n == 1) return BigInt(1)

    var a = BigInt(0)
    var b = BigInt(1)
    for (_ <- 2 to n) { // Loop from 2 up to n
      val next = a + b
      a = b
      b = next
    }
    b
  }

  // Function to generate the first 'count' Fibonacci numbers
  def generateFibonacciSequence(count: Int): Seq[BigInt] = {
    if (count < 0) throw new IllegalArgumentException("Count must be non-negative")
    (0 until count).map(fibonacciIterative) // Use map on a range
    // Alternative using Stream (lazy evaluation):
    // lazy val fibs: Stream[BigInt] = BigInt(0) #:: BigInt(1) #:: fibs.zip(fibs.tail).map { case (a, b) => a + b }
    // fibs.take(count).toList
  }

  def main(args: Array[String]): Unit = {
    val n = 10
    println(s"Fibonacci number F($n): ${fibonacciIterative(n)}")

    val count = 15
    val sequence = generateFibonacciSequence(count)
    println(s"First $count Fibonacci numbers: ${sequence.mkString(", ")}")

    // Example with a larger number requiring BigInt
    val largeN = 90
    println(s"Fibonacci number F($largeN): ${fibonacciIterative(largeN)}")

    try {
      fibonacciIterative(-1)
    } catch {
      case e: IllegalArgumentException => println(s"Caught expected error: ${e.getMessage}")
    }
  }
}

