import scala.math.BigInt // Necessary for factorials > 20

object FactorialDemo {

  // Iterative function to calculate factorial N!
  // Returns BigInt to handle large numbers.
  def factorial(n: Int): BigInt = {
    if (n < 0) {
      throw new IllegalArgumentException("Factorial is not defined for negative numbers.")
    }
    var result = BigInt(1)
    // Iterate from 1 up to n
    for (i <- 1 to n) { // 'to' includes n
      result *= i
    }
    result
  }

  // Recursive version (less efficient for large n due to stack, but common example)
  // Requires BigInt multiplication. Tail recursion possible but more complex with BigInt.
  // def factorialRecursive(n: Int): BigInt = {
  //   if (n < 0) throw new IllegalArgumentException("Negative input")
  //   else if (n == 0) BigInt(1)
  //   else BigInt(n) * factorialRecursive(n - 1)
  // }

  def main(args: Array[String]): Unit = {
    val num1 = 5
    println(s"Factorial of $num1 is: ${factorial(num1)}")

    val num2 = 0
    println(s"Factorial of $num2 is: ${factorial(num2)}")

    val num3 = 20 // Max for standard Long
    println(s"Factorial of $num3 is: ${factorial(num3)}")

