import scala.math.{sqrt, BigInt} // sqrt works on Double, BigInt needed if checking very large numbers

object PrimeCheckDemo {

  // Function to check if a number is prime
  def isPrime(n: Long): Boolean = {
    if (n <= 1) return false // Primes are greater than 1
    if (n <= 3) return true  // 2 and 3 are prime
    if (n % 2 == 0 || n % 3 == 0) return false // Exclude multiples of 2 and 3

    // Check potential divisors from 5 upwards, stepping by 6 (i, i+2)
    // Only need to check up to the square root of n
    val limit = sqrt(n.toDouble).toLong
    var i = 5L // Start checking from 5
    while (i <= limit) {
      if (n % i == 0 || n % (i + 2) == 0) {
        return false // Divisor found
      }
      i += 6 // Step by 6
    }
    true // No divisors found
  }

  // Example using BigInt for very large numbers (isPrime logic is similar)
  def isPrimeBigInt(n: BigInt): Boolean = {
      if (n <= 1) return false
      if (n <= 3) return true
      if (n % 2 == 0 || n % 3 == 0) return false

      // Need BigInt specific sqrt - not trivial, often involves iteration or external libs
      // For simplicity here, we might rely on probabilistic tests for very large BigInts
      // Or use a simpler limit if performance allows
