      // Simple check (less efficient for huge BigInts):
      var i = BigInt(5)
      // A simple limit example (not mathematically rigorous sqrt for BigInt)
      // val limit = n / 2 // Or a better approximation if needed
      // isProbablePrime is a better choice for BigInt
      n.isProbablePrime(certainty = 100) // High certainty probabilistic test

      // Manual check loop (demonstration, use isProbablePrime in practice)
      // val limitApprox = BigInt(sqrt(n.doubleValue).toLong) // Approximation, can fail
      // while (i * i <= n) { // Compare squares to avoid sqrt
      //   if (n % i == 0 || n % (i + 2) == 0) return false
      //   i += 6
      // }
      // true
  }


  def main(args: Array[String]): Unit = {
    val numbersToCheck = List(2L, 3L, 4L, 17L, 25L, 29L, 97L, 100L, 1L, -5L, 1000000007L) // 1,000,000,007 is prime

    println("--- Checking Long values ---")
    numbersToCheck.foreach { n =>
      if (isPrime(n)) {
        println(s"$n is prime.")
      } else {
        println(s"$n is not prime.")
      }
    }

    println("\n--- Checking BigInt values (using isProbablePrime) ---")
    val bigNumbers = List(BigInt(2), BigInt(17), BigInt("104729"), BigInt("104730"), BigInt("7919") * BigInt("7907"))
    bigNumbers.foreach { n =>
        if (isPrimeBigInt(n)) { // Using probabilistic test for BigInt
             println(s"$n is probable prime.")
         } else {
             println(s"$n is composite.")
         }
    }
  }
}

