import scala.io.Source // For reading files
import scala.util.{Using, Try, Success, Failure} // Using for resource management (Scala 2.13+)
import java.io.{File, PrintWriter, FileNotFoundException, IOException}

object ReadFileDemo {
  def main(args: Array[String]): Unit = {
    val filename = "scala_read_test.txt"

    // Create a dummy file for reading
    Try {
      Using.resource(new PrintWriter(filename)) { writer =>
        writer.println("First line from Scala.")
        writer.println("Second line here.")
        writer.println("你好世界") // Unicode example
      }
    } match {
      case Success(_) => println(s"Created dummy file '$filename'")
      case Failure(e) => println(s"Failed to create dummy file: ${e.getMessage}"); return
    }

    println(s"--- Reading file '$filename' ---")

    // Method 1: Read all lines into a List[String] using scala.util.Using (safe resource handling)
    val linesTry: Try[List[String]] = Using(Source.fromFile(filename)) { source =>
      source.getLines().toList // Read all lines into a list
    }

    linesTry match {
      case Success(lines) =>
        println("Content read line by line:")
        lines.zipWithIndex.foreach { case (line, index) =>
          println(s"Line ${index + 1}: $line")
        }
      case Failure(_: FileNotFoundException) =>
        println(s"Error: File not found '$filename'")
      case Failure(e: IOException) =>
        println(s"Error reading file '$filename': ${e.getMessage}")
      case Failure(e) =>
        println(s"An unexpected error occurred: ${e.getMessage}")
    }

    // Method 2: Read the entire file into a single String using scala.util.Using
    val contentTry: Try[String] = Using(Source.fromFile(filename)) { source =>
      source.mkString // Read the whole file content as one string
    }

    contentTry match {
      case Success(content) =>
        println("\nEntire file content as a single string:")
        println(content)
        println("--- End of content ---")
      case Failure(e) => // Error handled above, but shown for completeness
         println(s"Error reading entire content: ${e.getMessage}")
    }

    // Clean up the dummy file
    Try(new File(filename).delete()) match {
        case Success(true) => println(s"\nCleaned up dummy file '$filename'.")
        case Success(false) => println(s"\nCould not delete dummy file '$filename' (might not exist).")
        case Failure(e) => println(s"\nError cleaning up dummy file: ${e.getMessage}")
    }
  }
}

