import scala.util.{Using, Try, Success, Failure}
import java.io.{File, PrintWriter, FileWriter, IOException}

object WriteFileDemo {
  def main(args: Array[String]): Unit = {
    val filename = "output_scala.txt"
    val line1 = "First line written using Scala."
    val line2 = "This is the second line, with Unicode: éàçü."
    val appendLine = "This line was appended later."

    // --- Write using PrintWriter (overwrites or creates) ---
    // Using.resource ensures the writer is closed automatically
    println(s"--- Writing to '$filename' (overwrite) ---")
    val writeTry = Using(new PrintWriter(new File(filename))) { writer =>
      writer.println(line1) // println adds a newline
      writer.write(line2)    // write does not add a newline
      writer.write("\n")      // Manually add newline if needed after write
      // writer.flush() // Often not needed with Using, close() usually flushes
    }

    writeTry match {
      case Success(_) => println("Successfully wrote initial content.")
      case Failure(e: IOException) => println(s"Error writing to file: ${e.getMessage}")
      case Failure(e) => println(s"An unexpected error occurred during write: ${e.getMessage}")
    }

    // --- Append using FileWriter and PrintWriter ---
    println(s"\n--- Appending to '$filename' ---")
    // FileWriter constructor with 'true' for append mode
    val appendTry = Using(new PrintWriter(new FileWriter(filename, true))) { writer =>
      writer.println(appendLine) // Append the line with a newline
    }

    appendTry match {
      case Success(_) => println("Successfully appended content.")
      case Failure(e: IOException) => println(s"Error appending to file: ${e.getMessage}")
      case Failure(e) => println(s"An unexpected error occurred during append: ${e.getMessage}")
    }

    // --- Display final content (by reading it back - example) ---
    println(s"\n--- Final content of '$filename' (read back): ---")
    Try(Using.resource(scala.io.Source.fromFile(filename))(_.mkString)) match {
      case Success(content) => print(content) // Use print to avoid extra final newline
      case Failure(e) => println(s"Error reading back file: ${e.getMessage}")
    }

    // Optional: Clean up the created file
    // Try(new File(filename).delete())
  }
}

