import java.io.File
import java.io.PrintWriter // To create dummy files/dirs
import scala.util.Try

object FileExistsDemo {
  def main(args: Array[String]): Unit = {
    val fileToCheck = "scala_exists_test.scala"
    val dirToCheck = "my_scala_dir"
    val nonExistent = "no_such_scala_thing.ext"

    // --- Setup: Create dummy file and directory ---
    val file = new File(fileToCheck)
    val dir = new File(dirToCheck)
    Try {
      // Create file
      Using.resource(new PrintWriter(file)) { writer => writer.println("// Scala test file") }
      // Create directory
      if (!dir.exists()) dir.mkdirs() // Use mkdirs for parent dirs if needed
      println(s"Created dummy file '$fileToCheck' and directory '$dirToCheck'")
    }.recover { case e => println(s"Error during setup: ${e.getMessage}") }


    println("\n--- Checking Existence and Type ---")

    // Check existence using java.io.File
    val fCheck = new File(fileToCheck)
    val dCheck = new File(dirToCheck)
    val nCheck = new File(nonExistent)

    // file.exists() - Checks if path exists (file, dir, etc.)
    println(s"'$fileToCheck' exists? ${fCheck.exists()}")
    println(s"'$dirToCheck' exists? ${dCheck.exists()}")
    println(s"'$nonExistent' exists? ${nCheck.exists()}")

    // file.isFile() - Checks if path exists AND is a regular file
    println(s"\n'$fileToCheck' is file? ${fCheck.isFile()}")
    println(s"'$dirToCheck' is file? ${dCheck.isFile()}") // Should be false

    // file.isDirectory() - Checks if path exists AND is a directory
    println(s"\n'$fileToCheck' is directory? ${fCheck.isDirectory()}") // Should be false
    println(s"'$dirToCheck' is directory? ${dCheck.isDirectory()}")

    // --- Cleanup ---
    Try {
      if (fCheck.exists()) fCheck.delete()
      if (dCheck.exists()) dCheck.delete() // Use delete for empty dir
      println("\nCleaned up dummy file and directory.")
    }.recover { case e => println(s"Error during cleanup: ${e.getMessage}") }

    // Note: For more advanced file operations (listing, non-empty dir deletion),
    // consider Java NIO Path API or external libraries like better-files.
  }

  // Helper for Using.resource in Scala < 2.13 if not available
  object Using {
    def resource[R <: AutoCloseable, A](closeable: R)(f: R => A): Try[A] = {
      Try(f(closeable)).transform(
        result => { Try(closeable.close()).map(_ => result) },
        exception => {
          Try(closeable.close()).recover { case closeException => /* Log or add suppressed? */ exception.addSuppressed(closeException) }
          Failure(exception)
        }
      )
    }
  }
}

maxInArray:
object MaxInArrayDemo {
  def main(args: Array[String]): Unit = {

    // Example with Array[Int]
    val numbers: Array[Int] = Array(10, 5, 42, 17, 8, 99, 32, -5, 0)
    println(s"Integer Array: ${numbers.mkString(", ")}")

    if (numbers.isEmpty) {
      println("Array is empty, cannot find maximum.")
    } else {
      // .max finds the maximum element
      // Throws java.lang.UnsupportedOperationException if the array is empty
      val maxValue = numbers.max
      println(s"Maximum value: $maxValue")

      // Safer way using maxOption (returns Option[Int])
      val maxOpt: Option[Int] = numbers.maxOption
      maxOpt match {
        case Some(maxVal) => println(s"Maximum value (using maxOption): $maxVal")
        case None => println("Array was empty (using maxOption).") // Should not happen here
      }
    }

    // Example with empty Array
    val emptyArray: Array[Int] = Array.empty[Int]
    println(s"\nEmpty Array: ${emptyArray.mkString(", ")}")
    emptyArray.maxOption match {
      case Some(maxVal) => println(s"Maximum value: $maxVal") // Won't be reached
      case None => println("Array is empty, cannot find maximum (using maxOption).")
    }
    // Calling .max on emptyArray would throw an exception

    // Example with List[Double]
    val floats: List[Double] = List(1.5, -0.5, 3.14, 2.71, 3.14159, 3.14)
    println(s"\nDouble List: ${floats.mkString(", ")}")
    if (floats.nonEmpty) {
      val maxFloat = floats.max
      println(s"Maximum value: $maxFloat")
    }

    // Example with List[String] (lexicographical comparison)
    val strings: List[String] = List("apple", "banana", "Cherry", "Date", "Banana")
    println(s"\nString List: ${strings.mkString(", ")}")
    if (strings.nonEmpty) {
      val maxString = strings.max // Case-sensitive comparison by default
      println(s"Maximum value (lexicographical): $maxString") // Expect "banana"
    }

    // Finding max using a custom ordering (e.g., case-insensitive string length)
    case class Person(name: String, age: Int)
    val people = List(Person("Alice", 30), Person("Bob", 25), Person("Charlie", 35))
    println(s"\nPeople List: $people")
    if(people.nonEmpty) {
        // Find person with max age
        val oldestPerson = people.maxBy(_.age) // Find element where the function result is max
        println(s"Oldest person: $oldestPerson")
    }

  }
}
